var ws={server:null,taskId:null,canReload:true,init:function(){$(".c-task-current").click(function(a){ws.taskId=$(this).data("taskId");a.stopPropagation()});$(".c-task-comment").click(function(b){var a=$(this);b.stopPropagation();b.preventDefault();$.ajax({type:"post",dataType:"json",data:{action:"taskPrepare",taskId:$(this).data("taskId")},success:function(c){if(c.success){$("#i-div-task-detail-"+a.data("taskId")).html(c.html).slideDown()}},error:function(){}})});$("body").focusin(function(){if(ws.taskId!=null){var a=ws.taskId;ws.taskId=null;$("#i-div-task-"+a).slideUp("slow",function(){$.ajax({type:"post",dataType:"json",data:{action:"taskCheck",taskId:a},beforeSend:function(){$("#i-div-task-detail-"+a).hide()},success:function(b){if(b.success){if(b.bonus){location.reload()}$("#i-div-task-"+a).remove();$("#i_header_balance").html(b.balance);$(".loadbar").css({width:b.karma+"%"});$(".karma .index").html("Карма "+b.karmaText+"%");if(b.html){$("#i-div-tasks-list").append(b.html)}}else{$("#i-div-task-"+a).slideDown();if(b.errorText){$("#i-div-task-detail-"+a).html(b.errorText).show()}}a=null},error:function(){$("#i-div-task-"+a).slideDown().addClass("alert alert-danger");a=null},complete:function(){ws.canReload=true}})})}})}};$(document).ready(function(){ws.init()});